var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"죽인다……. 다음에 잡으면 반드시 죽인다…….","JPN":"殺す……次に会う時必ず殺してやる……","ENG":"She's dead... She's a dead woman the next time I see her...","TWN":"我要殺了你……下次被我逮到絕對要殺了你……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후우……. 나 왔어.","JPN":"ふう……ただいま。","ENG":"*Sigh* I'm back.","TWN":"哀……我來了。"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"왔어요, 사장님? 의뢰비는요?","JPN":"おかえりなさい、社長。報酬はちゃんともらってきました？","ENG":"Welcome back, Boss. Where's our money?","TWN":"老闆你來啦，這次的委託費呢？"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……뭐지? 데자뷔인가?","JPN":"……なんだ？　デジャブか？","ENG":"Huh? I think I'm having a déjà vu.","TWN":"……這是什麼既視感？"},"stage":{"bg":"DATABASE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"……그럼, 의뢰인이 다시 쫓아오지는 않았어요?","JPN":"……で、また依頼主が追いかけてきたりしませんでしたか？","ENG":"... Then, didn't the client come back for you?","TWN":"……是喔，那委託人沒有追上來嗎？"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다행히 아직은 잠잠해.","JPN":"幸いまだ動きはない。","ENG":"Not yet, fortunately.","TWN":"好險目前都還沒什麼動作！"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐, 아무리 날뛰어도 리플레이서 잔당들보다는 낫겠지.","JPN":"まあ、いくら暴れてもリプレイサーの残党よりはマシだろう。","ENG":"Well, even if he does, he can't be worse than the Replacer remnants.","TWN":"不過再怎麼樣，他們還是比克隆集團的傢伙好對付啦～"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"의뢰비도 못 받고, 침식체 상대한다고 특수탄도 엄청 쓰셨지만요.","JPN":"依頼費ももらえず、侵食体用の時殊弾もたっぷり使ったようですが。","ENG":"But he didn't pay you. And you spent a lot of special bullets on his C.O., too.","TWN":"只是你錢沒收到，然後為了對付侵蝕體又用掉很多特殊彈。"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"크흠. 그나마 제인이 마스코트 인형 안에 돈을 좀 넣어 뒀더군.","JPN":"まあでも、ジェーンがマスコットのぬいぐるみの中にお金を少し入れていたみたいだ。","ENG":"Kahem. But Jane left some money inside that mascot doll.","TWN":"咳咳，這次至少珍妮有在娃娃裡面塞一些錢。"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"분하지만 이걸로 일단 헴스워스 영감님에게 줄 외상값은 틀어막아야지.","JPN":"悔しいが、とりあえずヘムズワース爺に返す代金は何とかなりそうだ。","ENG":"I'm still angry with her, but I can use the money to pay Helmsworth.","TWN":"雖然很生氣，不過起碼可以先把欠漢姆沃斯的錢還掉吧？"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"이번달치 외상을 갚으면 어떻게 되는지 아세요?","JPN":"今月分の返済が終わるとどうなるか知っていますか？","ENG":"Do you know what happens if you pay him this month?","TWN":"這個月的還完後，你知道會怎樣嗎？"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……다음달치 외상을 갚아야겠지.","JPN":"……来月分の返済が始まる。","ENG":"... I'll have made one more payment on what I owe?","TWN":"……就是要還下個月的。"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"그것만이면 다행이게요. 공과금도 못 낸 지 한참 됐다고요.","JPN":"それだけならまだマシです。光熱費も未払いのまま結構経っていますよ。","ENG":"His money isn't the only problem. There are other bills we haven't paid. For months.","TWN":"那還只是小事，稅金都多久沒繳了。"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"돈 얘기는 나중에 해 줘. 지금은 그냥…….","JPN":"お金の話は後にしてくれ。今はただ……","ENG":"Can we talk about money later? For now, I want to—","TWN":"先不要跟我談錢的事，我要先……"},"stage":{"bg":"DATABASE","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"응? 갑자기 왜 불이 꺼져? 정전인가?","JPN":"うん？　急になんだ？　停電か？","ENG":"Erm, the lights went out all of a sudden. Are we having a power outage?","TWN":"嗯？怎麼突然變暗？是停電嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"전기가 끊긴 걸 거예요. 경고장 몇 번 왔거든요.","JPN":"電気を止められたのでしょう。督促状が何回も届いていましたよ。","ENG":"The power company probably cut off our electricity. We've gotten the final notice several times.","TWN":"是被斷電啦！都收到好幾張停電通知了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……왜 목숨 걸고 일할수록 내 재정 상황은 더 파탄 나는 거지?","JPN":"……なぜ命がけで働くほど、俺の経済状況はどんどん破綻していくのだろう?","ENG":"How come I'm struggling more the harder I work?","TWN":"……為什麼我越是拼命幹活兒，我的財務狀況就越悽慘？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};